271   void copysign(const KnownFPClass &Sign) {
272     // Don't know anything about the sign of the source. Expand the possible set
273     // to its opposite sign pair.
274     if (KnownFPClasses & fcZero)
275       KnownFPClasses |= fcZero;
276     if (KnownFPClasses & fcSubnormal)
277       KnownFPClasses |= fcSubnormal;
278     if (KnownFPClasses & fcNormal)
279       KnownFPClasses |= fcNormal;
280     if (KnownFPClasses & fcInf)
281       KnownFPClasses |= fcInf;
282 
283     // Sign bit is exactly preserved even for nans.
284     SignBit = Sign.SignBit;
285 
286     // Clear sign bits based on the input sign mask.
287     if (Sign.isKnownNever(fcPositive | fcNan) || (SignBit && *SignBit))
288       KnownFPClasses &= (fcNegative | fcNan);
289     if (Sign.isKnownNever(fcNegative | fcNan) || (SignBit && !*SignBit))
290       KnownFPClasses &= (fcPositive | fcNan);
291   }
