293   // Propagate knowledge that a non-NaN source implies the result can also not
294   // be a NaN. For unconstrained operations, signaling nans are not guaranteed
295   // to be quieted but cannot be introduced.
296   void propagateNaN(const KnownFPClass &Src, bool PreserveSign = false) {
297     if (Src.isKnownNever(fcNan)) {
298       knownNot(fcNan);
299       if (PreserveSign)
300         SignBit = Src.SignBit;
301     } else if (Src.isKnownNever(fcSNan))
302       knownNot(fcSNan);
303   }
